import { PageContainer } from '@ant-design/pro-layout';
import { Link, useParams } from '@umijs/max';
import { useEffect, useState } from 'react';
import { getDeviceGroupByGuid } from '@/services/api';
import { API } from '@/services/typings';
import { Breadcrumb } from 'antd';
import DevicesTable from './DevicesTable';
import { t } from '@/global';

const DeviceGroupDeviceList: React.FC = () => {
  // https://umijs.org/blog/develop-blog-using-umi#api-%E8%B7%AF%E7%94%B1%E8%AE%BE%E8%AE%A1
  // https://github.com/umijs/umi-blog-example/blob/main/src/pages/posts/post.tsx
  // https://umijs.org/docs/api/api#useparams
  const params = useParams();
  const device_group_guid = params.device_group_guid as string;
  const [group, setGroup] = useState<API.GroupListItem>();

  useEffect(() => {
    getDeviceGroup();
  }, []);

  const getDeviceGroup = async () => {
    try {
      const group = await getDeviceGroupByGuid(device_group_guid);
      setGroup(group);
    } catch (error) { }
  }

  return (
    < PageContainer
      header={{
        title: group?.name,
        ghost: true,
      }}
      breadcrumbRender={() => <Breadcrumb items={[{
        title: <Link to="/groups/device">{t('menu.list.group-list.device')}</Link>
      },
      {
        title: group?.name,
      },]} />}
    >
      {group && <DevicesTable group={group} />}
    </PageContainer >
  )
};

export default DeviceGroupDeviceList;
