import { Button, message } from 'antd';
import { SelectOutlined } from '@ant-design/icons';
import React, { useState, useRef, Fragment, useEffect } from 'react';
import { FooterToolbar } from '@ant-design/pro-layout';
import type { ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { devices, deviceGroupDeleteDevices, deviceGroupAddDevices, groups } from '@/services/api';
import { API } from '@/services/typings';
import { useModel } from '@umijs/max';
import { t, renderDetails, getTablePaginationConfig, GroupTypeDevice, NamesPurpose_ChangeDeviceGroup } from '../../../global';
import { DEVICE_LIST_SORT_STATE_KEY, deviceColumns, NameEditor } from '@/pages/DeviceList/DevicesTable';
import DeviceSelect from './DeviceSelect';
import { getLocalSortState, handleSortStateChange } from '@/components/Others/table_sort';
import MyModalConfirm from '@/components/Others/MyModalConfirm';
import { ModalForm } from '@ant-design/pro-form';
import { hasGlobalPermChangeDeviceGroup } from '@/pages/RoleList/permissionUtils';

type DeviceGroupDeviceListProps = {
  group: API.GroupListItem;
}
const DevicesTable: React.FC<DeviceGroupDeviceListProps> = (props) => {
  const [showDetail, setShowDetail] = useState<boolean>(false);
  const actionRef = useRef<ActionType>();
  const [currentRow, setCurrentRow] = useState<API.DeviceListItem>();
  const [selectedRowsState, setSelectedRows] = useState<API.DeviceListItem[]>([]);
  const [deviceSelectVisible, setDeviceSelectVisible] = useState<boolean>(false);
  const { initialState } = useModel('@@initialState');
  const canChangeDeviceGroup = hasGlobalPermChangeDeviceGroup(initialState?.user);
  const [sortState, setSortState] = useState<API.SortState>(() => getLocalSortState(DEVICE_LIST_SORT_STATE_KEY));
  const [totalRecords, setTotalRecords] = useState<number>(0);
  const [MoveModalVisible, setMoveModalVisible] = useState<boolean>(false);
  const [moveIds, setMoveIds] = useState<string[]>([]);

  useEffect(() => {
    actionRef.current?.reload();
  }, []);

  const DeleteConfirm = (props: { children: any; onClick: () => void }) => (
    <MyModalConfirm
      title={t('deleteConfirm', true, 'Are you sure to delete?')}
      onConfirm={() => props.onClick()}
      okText="Yes"
      cancelText="No"
    >
      {props.children}
    </MyModalConfirm>
  );

  const handleDelete = async (rows: API.DeviceListItem[]) => {
    const hide = message.loading(t('Deleting'));
    try {
      await deviceGroupDeleteDevices(
        props.group.guid,
        {
          data: rows.map((x) => x.id),
        },
      );
      hide();
      message.success(t('Deletion is successful'));
      actionRef.current?.reloadAndRest?.();
      return true;
    } catch (error) {
      hide();
      message.error(
        typeof error == 'string' ? (error as string) : t('Deletion failed, please try again!'),
      );
      return false;
    }
  };

  const handleMove = async (values: Record<string, any>, ids: string[]) => {
    const groupName = values.name;
    if (!groupName) {
      message.error(t("Please select a group"));
      return;
    }
    if (groupName === props.group.name) {
      message.warning(t("Same group"));
      return;
    }
    const hide = message.loading(t('Updating'));
    try {
      const params = {
        current: 1,
        pageSize: 1,
        type: GroupTypeDevice,
        name: groupName,
      };
      const grps = await groups(params, undefined, true);
      if (grps.data?.length != 1) {
        hide();
        message.error(t("Unknown group"));
        return;
      }
      const target_grp = grps.data?.[0];
      if (!target_grp) {
        hide();
        message.error(t("Unknown group"));
        return;
      }
      if (target_grp.name !== groupName) {
        hide();
        message.error(t("Unknown group"));
        return;
      }
      await deviceGroupAddDevices(target_grp.guid, { data: ids });
      hide();
      message.success(`${ids.length} record${ids.length === 1 ? " is" : "s are"} successfully changed`)
    } catch (e: any) {
      hide();
      message.error(e);
    }
    actionRef.current?.clearSelected?.();
    actionRef.current?.reload();
    setMoveModalVisible(false);
  }


  const columns = deviceColumns({
    actionRef,
    user: initialState?.user,
    onIdClick: (entity: API.DeviceListItem) => {
      setCurrentRow(entity);
      setShowDetail(true);
    },
    totalRecords,
    sortState,
    setSortState,
    extraColumns: [
      {
        title: t('Action'),
        search: false,
        width: 120,
        hideInTable: !canChangeDeviceGroup,
        render: (text, record) => (
          <Fragment>
            <DeleteConfirm onClick={() => handleDelete([record])}>
              <a>{t('Delete')}</a>
            </DeleteConfirm>
          </Fragment>
        ),
      },
    ],
  })

  return (
    <div>
      <ProTable<API.DeviceListItem, API.PageParams & { device_group_guid: string }>
        headerTitle={t('Device List')}
        actionRef={actionRef}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'devicelist_columns_state' }}
        rowKey="id"
        search={{
          labelWidth: 120,
        }}
        params={{
          device_group_guid: props.group.guid,
        }}
        request={async (params, sort, _filter) => {
          const result = await devices(params, sort);
          setTotalRecords(result.total || 0);
          return result;
        }}
        columns={columns}
        toolBarRender={canChangeDeviceGroup ? () => [
          <Button
            type="primary"
            key="primary"
            onClick={() => {
              setDeviceSelectVisible(true);
            }}
          >
            <SelectOutlined /> {t('add_devices')}
          </Button>,

        ] : undefined}
        rowSelection={
          canChangeDeviceGroup
            ? {
              onChange: (_, selectedRows) => {
                setSelectedRows(selectedRows);
              },
            }
            : undefined
        }
        onChange={(_, __, sorter) => {
          handleSortStateChange(sorter, actionRef, DEVICE_LIST_SORT_STATE_KEY, setSortState);
        }}
        pagination={getTablePaginationConfig("device_list")}
      />
      {selectedRowsState?.length > 0 && (
        <FooterToolbar
          extra={
            <div>
              {t('Chosen')} <a style={{ fontWeight: 600 }}>{selectedRowsState.length}</a>{' '}
              {t('Items')}
            </div>
          }
        >
          <DeleteConfirm
            onClick={async () => {
              await handleDelete(selectedRowsState);
              setSelectedRows([]);
            }}
          >
            <Button>{t('Delete')}</Button>
          </DeleteConfirm>
          <Button onClick={() => {
            setMoveIds(selectedRowsState.map(row => row.id));
            setMoveModalVisible(true);
          }}>{t('move_to')}</Button>
        </FooterToolbar>
      )}
      {renderDetails(
        showDetail,
        currentRow?.guid,
        currentRow,
        columns.slice(0, columns.length - 1).filter((x) => x.title),
        setCurrentRow,
        setShowDetail,
      )}
      <DeviceSelect
        visible={deviceSelectVisible}
        setVisible={setDeviceSelectVisible}
        group={props.group}
        closeChangedCallback={() => {
          actionRef.current?.reload();
        }}
      ></DeviceSelect>
      <ModalForm
        title={t('move_to')}
        width="400px"
        open={MoveModalVisible}
        onOpenChange={setMoveModalVisible}
        onFinish={async (values) => {
          await handleMove(values, moveIds);
        }}
        modalProps={{
          maskClosable: false,
          destroyOnClose: true,
          onCancel: () => {
            setMoveModalVisible(false);
          },
        }}
      >
        <NameEditor table={"grp"} field={"name"} label={"Group"} required type={GroupTypeDevice} purpose={NamesPurpose_ChangeDeviceGroup} />
      </ModalForm>
    </div>
  );
};

export default DevicesTable;
